% BEGIN TZP DERIVATION LAYER
\tzpsection{Derivation Layer}
\begingroup\small
\paragraph{Primary Equation.}
\begin{equation}
Lk
=
\frac{1}{4\pi}
\oint_{C_1}
\oint_{C_2}
\frac{
(\mathbf{r}_1-\mathbf{r}_2)
\cdot
(\mathrm{d}\mathbf{r}_1\times \mathrm{d}\mathbf{r}_2)
}{
|\mathbf{r}_1-\mathbf{r}_2|^3
}.
\end{equation}

\paragraph{Primary Derivation.}
Let $C_1$ and $C_2$ be two closed magnetic flux tubes or field-line loops.  
The Gauss linking integral measures how many times the two loops wind around one another.

For points $\mathbf{r}_1\in C_1$ and $\mathbf{r}_2\in C_2$, the relative displacement is:

\begin{equation}
\mathbf{r}_1-\mathbf{r}_2 .
\end{equation}

The oriented area element generated by the two path differentials is:

\begin{equation}
\mathrm{d}\mathbf{r}_1\times \mathrm{d}\mathbf{r}_2 .
\end{equation}

Normalizing by the cubic separation gives the universal linking density:

\begin{equation}
\frac{
(\mathbf{r}_1-\mathbf{r}_2)
\cdot
(\mathrm{d}\mathbf{r}_1\times \mathrm{d}\mathbf{r}_2)
}{
|\mathbf{r}_1-\mathbf{r}_2|^3
}.
\end{equation}

The full linking number is:

\begin{equation}
\boxed{
Lk
=
\frac{1}{4\pi}
\oint_{C_1}
\oint_{C_2}
\frac{
(\mathbf{r}_1-\mathbf{r}_2)
\cdot
(\mathrm{d}\mathbf{r}_1\times \mathrm{d}\mathbf{r}_2)
}{
|\mathbf{r}_1-\mathbf{r}_2|^3
}.
}
\end{equation}

\paragraph{Wolfram Form.}
\begin{verbatim}
Lk == (1/(4*Pi))*
  Integrate[
    Dot[r1 - r2, Cross[dr1, dr2]]/Norm[r1 - r2]^3,
    {r1, C1}, {r2, C2}
  ]
\end{verbatim}

\paragraph{Interpretation.}
The linking number is integer-valued and topologically stable. It supplies the universal counting rule behind helicity quantisation.
\endgroup
% END TZP DERIVATION LAYER

